<script setup lang="ts">
import {computed,nextTick,onMounted,ref} from 'vue';
import {api} from '../api';
import Composer from '../components/Composer.vue';
import {Camera,ChevronDown,Database,LockKeyhole,LogOut,MessageSquare,Plus,Trash2,UserCog,X} from 'lucide-vue-next';

type Msg={id?:number,role:'user'|'assistant',text:string};
type Conversation={id:number,title:string,updatedAt:string};
const messages=ref<Msg[]>([]),conversations=ref<Conversation[]>([]),activeConversationId=ref<number>(),pendingDeleteConversation=ref<Conversation>(),deletingConversation=ref(false),busy=ref(false);
const messagesContainer=ref<HTMLElement>();
const showAccount=ref(false),showProfileMenu=ref(false),avatarUrl=ref(localStorage.getItem('avatarUrl')||'');
const passwordForm=ref({currentPassword:'',newPassword:'',confirmPassword:''}),accountMessage=ref('');
const displayName=localStorage.getItem('name')||'知识库用户',isAdmin=localStorage.getItem('role')==='ADMIN';
const activeConversation=computed(()=>conversations.value.find(x=>x.id===activeConversationId.value));

async function load(){conversations.value=(await api.get('/conversations')).data}
async function newChat(){const{data}=await api.post('/conversations');conversations.value=[data,...conversations.value];activeConversationId.value=data.id;messages.value=[]}
async function openConversation(c:Conversation){activeConversationId.value=c.id;messages.value=(await api.get(`/conversations/${c.id}/messages`)).data.map((m:any)=>({id:m.id,role:m.role,text:m.content}));await scrollToBottom()}
function requestDeleteConversation(c:Conversation,e:Event){e.stopPropagation();deletingConversation.value=false;pendingDeleteConversation.value=c}
async function confirmDeleteConversation(){const conversation=pendingDeleteConversation.value;if(!conversation||deletingConversation.value)return;deletingConversation.value=true;try{await api.delete(`/conversations/${conversation.id}`);conversations.value=conversations.value.filter(x=>x.id!==conversation.id);if(activeConversationId.value===conversation.id){activeConversationId.value=undefined;messages.value=[]}pendingDeleteConversation.value=undefined}finally{deletingConversation.value=false}}
async function ask(text:string){messages.value.push({role:'user',text});busy.value=true;await scrollToBottom();try{const{data}=await api.post('/chat',{conversationId:activeConversationId.value,question:text});activeConversationId.value=data.conversationId;messages.value.push({role:'assistant',text:data.answer});await load()}catch(error:any){messages.value.push({role:'assistant',text:error.response?.data?.message||'暂时无法连接 AI 服务，请稍后重试。'})}finally{busy.value=false;await scrollToBottom()}}
async function scrollToBottom(){await nextTick();const element=messagesContainer.value;if(element)element.scrollTo({top:element.scrollHeight,behavior:'smooth'})}
function logout(){localStorage.clear();location.href='/login'}
async function uploadAvatar(e:Event){const input=e.target as HTMLInputElement,file=input.files?.[0];if(!file)return;accountMessage.value='';if(file.size>2*1024*1024){accountMessage.value='头像不能超过 2MB';return}const form=new FormData();form.append('file',file);try{const{data}=await api.post('/profile/avatar',form);avatarUrl.value=data.url;localStorage.setItem('avatarUrl',data.url);accountMessage.value='头像更新成功'}catch(error:any){accountMessage.value=error.response?.data?.message||'头像上传失败'}finally{input.value=''}}
async function changePassword(){accountMessage.value='';if(passwordForm.value.newPassword!==passwordForm.value.confirmPassword){accountMessage.value='两次输入的新密码不一致';return}try{await api.put('/profile/password',{currentPassword:passwordForm.value.currentPassword,newPassword:passwordForm.value.newPassword});passwordForm.value={currentPassword:'',newPassword:'',confirmPassword:''};accountMessage.value='密码修改成功，下次登录请使用新密码'}catch(error:any){accountMessage.value=error.response?.data?.message||'密码修改失败'}}
onMounted(load);
</script>

<template><main class="app-shell"><aside class="sidebar"><div class="brand"><span class="brand-mark ggbond-logo"><img src="/ggbond-logo.jpg" alt="GGBOND logo"></span><span>GGBOND AI<small>KNOWLEDGE OS</small></span></div><button class="new-chat" @click="newChat"><Plus/>开启新对话</button><button class="module-entry" @click="$router.push('/knowledge')"><Database/>知识库管理</button><button v-if="isAdmin" class="module-entry" @click="$router.push('/users')"><UserCog/>用户管理</button><nav class="conversation-nav"><div class="nav-title"><span>最近对话</span><small>{{conversations.length}}</small></div><div class="conversation-list"><div v-for="c in conversations" :key="c.id" class="conversation-item" :class="{active:activeConversationId===c.id}" @click="openConversation(c)"><MessageSquare/><span>{{c.title}}</span><button type="button" title="删除对话" @click.stop="requestDeleteConversation(c,$event)"><Trash2/></button></div><p v-if="!conversations.length" class="conversation-empty">暂无对话，点击上方按钮开始第一次提问。</p></div></nav></aside>
  <section class="workspace"><header class="topbar"><div class="page-title"><b>AI 知识问答</b><span v-if="activeConversation">{{activeConversation.title}}</span></div><div class="top-actions"><span class="knowledge-status">自动检索全部可用知识库</span><div class="account-trigger" @click.stop><button type="button" @click.stop="showProfileMenu=!showProfileMenu"><span class="top-avatar"><img v-if="avatarUrl" :src="avatarUrl" alt="用户头像"><span v-else>{{displayName.slice(0,1)}}</span></span><span class="account-name"><b>{{displayName}}</b><small>{{isAdmin?'系统管理员':'普通用户'}}</small></span><ChevronDown/></button><div v-if="showProfileMenu" class="profile-menu" @click.stop><button type="button" @click="showAccount=true;showProfileMenu=false"><UserCog/><span><b>个人资料</b><small>头像与密码设置</small></span></button><button type="button" class="logout-action" @click="logout"><LogOut/><span><b>退出系统</b><small>安全退出当前账号</small></span></button></div></div></div></header>
    <div class="chat"><div v-if="!messages.length" class="welcome"><span class="eyebrow">KNOWLEDGE-ASSISTED AI</span><h1>从组织知识中找到准确答案</h1><p>直接提问，系统会自动检索所有有权限的知识库，并基于相关资料回答。</p></div><div v-else ref="messagesContainer" class="messages"><article v-for="(m,i) in messages" :key="m.id||i" :class="m.role"><div class="msg-avatar"><span v-if="m.role==='user'">我</span><img v-else src="/ggbond-logo.jpg" alt="GGBOND AI"></div><div><b>{{m.role==='user'?'你':'GGBOND AI'}}</b><p>{{m.text}}</p></div></article><article v-if="busy" class="assistant"><div class="msg-avatar"><img src="/ggbond-logo.jpg" alt="GGBOND AI"></div><div><b>GGBOND AI</b><p>正在检索知识…</p></div></article></div><div class="composer-wrap"><Composer :disabled="busy" @send="ask"/><small>AI 可能会犯错，请核对重要信息与引用来源。</small></div></div>
  </section>
  <div v-if="showAccount" class="modal-backdrop" @click.self="showAccount=false"><section class="modal account-modal"><button class="modal-close" @click="showAccount=false"><X/></button><span class="eyebrow">MY ACCOUNT</span><h2>个人资料</h2><div class="avatar-editor"><label><span class="account-avatar"><img v-if="avatarUrl" :src="avatarUrl" alt="头像"><span v-else>{{displayName.slice(0,1)}}</span><i><Camera/></i></span><input type="file" accept="image/jpeg,image/png,image/webp" @change="uploadAvatar"></label><div><b>{{displayName}}</b><small>{{isAdmin?'系统管理员':'普通用户'}}</small><p>点击头像更换，支持 JPG、PNG、WEBP，最大 2MB</p></div></div><div class="account-divider"></div><form class="password-form" @submit.prevent="changePassword"><h3><LockKeyhole/>修改密码</h3><label>当前密码<input v-model="passwordForm.currentPassword" type="password" required></label><label>新密码<input v-model="passwordForm.newPassword" type="password" required minlength="6"></label><label>确认新密码<input v-model="passwordForm.confirmPassword" type="password" required minlength="6"></label><p v-if="accountMessage" class="account-message">{{accountMessage}}</p><button class="primary">保存新密码</button></form></section></div>
  <div v-if="pendingDeleteConversation" class="modal-backdrop" @click.self="pendingDeleteConversation=undefined"><section class="conversation-delete-modal"><span><Trash2/></span><h2>删除对话</h2><p>确认删除对话“{{pendingDeleteConversation.title}}”吗？删除后无法恢复。</p><div><button type="button" :disabled="deletingConversation" @click="pendingDeleteConversation=undefined">取消</button><button type="button" class="confirm" :disabled="deletingConversation" @click="confirmDeleteConversation">{{deletingConversation?'正在删除…':'删除对话'}}</button></div></section></div>
</main></template>

<style scoped>
.messages .msg-avatar{overflow:hidden}.messages .msg-avatar img{display:block;width:100%;height:100%;object-fit:cover;object-position:center 43%;image-rendering:auto}.messages .assistant .msg-avatar{border:1px solid #eee5d9;background:#fff;box-shadow:0 5px 14px #5b43341c}
.conversation-delete-modal{width:min(420px,92vw);padding:30px;border-radius:20px;background:#fff;text-align:center;box-shadow:0 28px 90px #2d203a35}.conversation-delete-modal>span{width:50px;height:50px;margin:auto;border-radius:15px;background:#fff0f2;color:#c84d62;display:grid;place-items:center}.conversation-delete-modal>span svg{width:21px}.conversation-delete-modal h2{margin:14px 0 8px}.conversation-delete-modal p{margin:0;color:#807985;font-size:13px;line-height:1.7}.conversation-delete-modal>div{display:flex;justify-content:center;gap:10px;margin-top:24px}.conversation-delete-modal button{min-width:96px;border:0;border-radius:10px;padding:11px;background:#f1eef4;color:#67606c;font-weight:600}.conversation-delete-modal button.confirm{background:#c94c61;color:#fff}.conversation-delete-modal button:disabled{opacity:.55}
.messages article{display:grid;align-items:start;margin-bottom:24px}.messages article.assistant{grid-template-columns:40px minmax(0,1fr);gap:11px}.messages article.user{grid-template-columns:minmax(0,1fr) 40px;gap:11px}.messages .user .msg-avatar{grid-column:2;grid-row:1;background:linear-gradient(145deg,#8ec5ff,#5f9ee8);color:#fff;box-shadow:0 5px 14px #5f9ee82b}.messages .user>div:last-child{grid-column:1;grid-row:1;justify-self:end;display:flex;align-items:flex-end;flex-direction:column}.messages .assistant>div:last-child{justify-self:start;display:flex;align-items:flex-start;flex-direction:column}.messages article>div:last-child{max-width:min(72%,680px)}.messages article b{margin:0 6px 5px;color:#8b8491;font-size:10px;font-weight:500}.messages article p{position:relative;margin:0;padding:11px 14px;border-radius:5px 15px 15px 15px;line-height:1.75;font-size:13px;word-break:break-word;white-space:pre-wrap}.messages .assistant p{border:1px solid #e9e5ed;background:#fff;color:#48424d;box-shadow:0 6px 18px #3326420a}.messages .assistant p:before{content:'';position:absolute;left:-7px;top:10px;width:12px;height:12px;border-left:1px solid #e9e5ed;border-bottom:1px solid #e9e5ed;background:#fff;transform:rotate(45deg)}.messages .user p{border:1px solid #b9dcfa;border-radius:15px 5px 15px 15px;background:linear-gradient(145deg,#dff1ff,#cce8ff);color:#2f4d67;box-shadow:0 6px 18px #5798d211}.messages .user p:after{content:'';position:absolute;right:-7px;top:10px;width:12px;height:12px;border-top:1px solid #b9dcfa;border-right:1px solid #b9dcfa;background:#d4ebff;transform:rotate(45deg)}.messages .msg-avatar{position:relative;z-index:2;border-radius:12px;font-size:10px;font-weight:700}.messages .assistant .msg-avatar{background:linear-gradient(145deg,#7764c9,#5d49aa);color:#fff}.messages .assistant>div:last-child{padding:0;border:0;background:transparent;box-shadow:none}@media(max-width:700px){.messages article>div:last-child{max-width:84%}.messages article.user,.messages article.assistant{gap:8px}.messages article.user{grid-template-columns:minmax(0,1fr) 34px}.messages article.assistant{grid-template-columns:34px minmax(0,1fr)}.messages .msg-avatar{width:32px;height:32px}.messages article p{font-size:12px;padding:10px 12px}}
.workspace{height:100vh;min-height:0;overflow:hidden}.chat{position:relative;flex:1;min-height:0;height:0;width:100%;overflow:hidden}.messages{flex:1;width:100%;max-width:none;margin:0;height:0;min-height:0;overflow-y:auto;overscroll-behavior:contain;padding-left:max(4.5%,calc((100% - 840px)/2));padding-right:max(4.5%,calc((100% - 840px)/2));padding-bottom:170px;scrollbar-gutter:stable}.messages article{width:100%;max-width:840px;margin-left:auto;margin-right:auto}.composer-wrap{position:absolute;left:0;right:0;bottom:0;z-index:10}.welcome{max-height:100%;overflow-y:auto}.conversation-list{min-height:0;overflow-y:auto}.conversation-nav{min-height:0;overflow:hidden;display:flex;flex-direction:column}.sidebar{min-height:0;overflow:hidden}
.module-entry{margin-top:9px;border:1px solid #e5dfec;border-radius:11px;padding:10px 12px;background:#fff;color:#5d5668;display:flex;align-items:center;gap:9px;font-weight:600}.module-entry:hover{background:#f0ebf7}.module-entry svg{width:16px}.conversation-nav{margin-top:28px!important}.topbar{position:relative;z-index:50;overflow:visible}.page-title{display:flex;align-items:center;gap:12px}.page-title>span{max-width:320px;padding-left:12px;border-left:1px solid #e3dfe8;color:#8d8694;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.account-trigger{position:relative}.account-trigger>button{border:0;border-radius:12px;padding:5px;background:transparent;display:flex;align-items:center;gap:9px;color:#514b59}.account-trigger>button:hover{background:#f2eef7}.account-trigger>button>svg{width:14px}.top-avatar{width:38px;height:38px;border-radius:12px;overflow:hidden;background:#e8e0f3;color:#6755a2;display:grid;place-items:center;font-weight:700}.top-avatar img,.account-avatar img{width:100%;height:100%;object-fit:cover}.account-name{display:flex;min-width:88px;flex-direction:column;text-align:left}.account-name b{font-size:11px}.account-name small{font-size:9px;color:#938c9a}.profile-menu{position:absolute;right:0;top:50px;width:220px;padding:7px;border:1px solid #e7e1ed;border-radius:14px;background:#fff;box-shadow:0 18px 50px #35274620;z-index:100}.profile-menu button{width:100%;border:0;border-radius:10px;padding:10px;background:transparent;display:flex;align-items:center;gap:10px;text-align:left;color:#514a57}.profile-menu button:hover{background:#f5f1f8}.profile-menu button>svg{width:17px}.profile-menu button>span{display:flex;flex-direction:column}.profile-menu b{font-size:11px}.profile-menu small{color:#9a939f;font-size:9px}.profile-menu .logout-action{margin-top:4px;color:#b44c5d}.account-modal{width:min(520px,92vw)}.avatar-editor{margin-top:24px;padding:16px;border:1px solid #ebe6ef;border-radius:16px;background:#faf8fc;display:flex;align-items:center;gap:16px}.avatar-editor label{margin:0}.avatar-editor input{display:none}.account-avatar{position:relative;width:76px;height:76px;border-radius:22px;overflow:hidden;background:#e9e2f3;color:#65549b;display:grid;place-items:center;font-size:24px;font-weight:700;cursor:pointer}.account-avatar i{position:absolute;right:3px;bottom:3px;width:25px;height:25px;border:2px solid #fff;border-radius:8px;background:#7060bd;color:#fff;display:grid;place-items:center}.account-avatar i svg{width:13px}.avatar-editor>div{display:flex;flex-direction:column}.avatar-editor small{color:#7f7588}.avatar-editor p{margin:8px 0 0;color:#a098a5;font-size:10px}.account-divider{height:1px;margin:24px 0;background:#ece8ef}.password-form h3{display:flex;align-items:center;gap:8px}.password-form h3 svg{width:18px}.password-form label{margin-top:13px}.password-form .primary{width:100%;margin-top:20px}.account-message{padding:9px 11px;border-radius:9px;background:#f2eef8;color:#67569d;font-size:11px}@media(max-width:760px){.knowledge-status,.account-name{display:none}.topbar{padding:0 14px}.page-title>span{display:none}}
</style>
